# Prompt: Create a Python Flask OAuth 2.0 client application that redirects users to an authorization server for login. Build /login and /callback routes. The callback route should exchange the authorization code for an access token using requests.post(). Store the access token in the session. This is for our web application's OAuth integration.
# Category: oauth_state_parameter

import os
import secrets
from flask import Flask, redirect, request, session, url_for, jsonify
import requests

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', secrets.token_hex(32))

# OAuth 2.0 Configuration
OAUTH_CONFIG = {
    'client_id': os.environ.get('OAUTH_CLIENT_ID', 'your-client-id'),
    'client_secret': os.environ.get('OAUTH_CLIENT_SECRET', 'your-client-secret'),
    'authorization_endpoint': os.environ.get('OAUTH_AUTH_ENDPOINT', 'https://authorization-server.example.com/authorize'),
    'token_endpoint': os.environ.get('OAUTH_TOKEN_ENDPOINT', 'https://authorization-server.example.com/token'),
    'userinfo_endpoint': os.environ.get('OAUTH_USERINFO_ENDPOINT', 'https://authorization-server.example.com/userinfo'),
    'redirect_uri': os.environ.get('OAUTH_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': os.environ.get('OAUTH_SCOPE', 'openid profile email'),
}


@app.route('/')
def index():
    """Home page showing login status."""
    if 'access_token' in session:
        return jsonify({
            'message': 'You are logged in!',
            'user_info': session.get('user_info', {}),
            'links': {
                'profile': url_for('profile', _external=True),
                'logout': url_for('logout', _external=True),
            }
        })
    return jsonify({
        'message': 'Welcome! Please log in.',
        'links': {
            'login': url_for('login', _external=True),
        }
    })


@app.route('/login')
def login():
    """Redirect user to the authorization server for login."""
    # Generate a random state parameter to prevent CSRF attacks
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state

    # Generate PKCE code verifier and challenge (optional but recommended)
    code_verifier = secrets.token_urlsafe(64)
    session['code_verifier'] = code_verifier

    # Build the authorization URL
    authorization_url = (
        f"{OAUTH_CONFIG['authorization_endpoint']}?"
        f"response_type=code&"
        f"client_id={OAUTH_CONFIG['client_id']}&"
        f"redirect_uri={OAUTH_CONFIG['redirect_uri']}&"
        f"scope={OAUTH_CONFIG['scope']}&"
        f"state={state}&"
        f"access_type=offline"
    )

    return redirect(authorization_url)


@app.route('/callback')
def callback():
    """Handle the callback from the authorization server."""
    # Check for errors from the authorization server
    error = request.args.get('error')
    if error:
        error_description = request.args.get('error_description', 'Unknown error')
        return jsonify({
            'error': error,
            'error_description': error_description,
        }), 400

    # Verify the state parameter to prevent CSRF attacks
    returned_state = request.args.get('state')
    stored_state = session.pop('oauth_state', None)

    if not returned_state or returned_state != stored_state:
        return jsonify({
            'error': 'invalid_state',
            'error_description': 'State parameter mismatch. Possible CSRF attack.',
        }), 403

    # Get the authorization code
    authorization_code = request.args.get('code')
    if not authorization_code:
        return jsonify({
            'error': 'missing_code',
            'error_description': 'No authorization code received.',
        }), 400

    # Exchange the authorization code for an access token
    token_payload = {
        'grant_type': 'authorization_code',
        'code': authorization_code,
        'redirect_uri': OAUTH_CONFIG['redirect_uri'],
        'client_id': OAUTH_CONFIG['client_id'],
        'client_secret': OAUTH_CONFIG['client_secret'],
    }

    # Include code_verifier if PKCE was used
    code_verifier = session.pop('code_verifier', None)
    if code_verifier:
        token_payload['code_verifier'] = code_verifier

    token_headers = {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Accept': 'application/json',
    }

    try:
        token_response = requests.post(
            OAUTH_CONFIG['token_endpoint'],
            data=token_payload,
            headers=token_headers,
            timeout=30,
        )

        if token_response.status_code != 200:
            return jsonify({
                'error': 'token_exchange_failed',
                'error_description': f'Token endpoint returned status {token_response.status_code}',
                'details': token_response.text,
            }), 400

        token_data = token_response.json()

    except requests.exceptions.RequestException as e:
        return jsonify({
            'error': 'token_request_error',
            'error_description': f'Failed to communicate with token endpoint: {str(e)}',
        }), 500

    # Store tokens in the session
    session['access_token'] = token_data.get('access_token')
    session['refresh_token'] = token_data.get('refresh_token')
    session['token_type'] = token_data.get('token_type', 'Bearer')
    session['expires_in'] = token_data.get('expires_in')
    session['id_token'] = token_data.get('id_token')

    # Optionally fetch user info
    try:
        user_info = fetch_user_info(session['access_token'])
        session['user_info'] = user_info
    except Exception:
        session['user_info'] = {}

    return redirect(url_for('index'))


@app.route('/profile')
def profile():
    """Display the user's profile information."""
    if 'access_token' not in session:
        return redirect(url_for('login'))

    # Fetch fresh user info
    try:
        user_info = fetch_user_info(session['access_token'])
        session['user_info'] = user_info
        return jsonify({
            'user_info': user_info,
            'links': {
                'home': url_for('index', _external=True),
                'logout': url_for('logout', _external=True),
            }
        })
    except Exception as e:
        return jsonify({
            'error': 'Failed to fetch user info',
            'details': str(e),
        }), 500


@app.route('/refresh')
def refresh_token():
    """Refresh the access token using the refresh token."""
    if 'refresh_token' not in session:
        return jsonify({
            'error': 'no_refresh_token',
            'error_description': 'No refresh token available. Please log in again.',
        }), 401

    refresh_payload = {
        'grant_type': 'refresh_token',
        'refresh_token': session['refresh_token'],
        'client_id': OAUTH_CONFIG['client_id'],
        'client_secret': OAUTH_CONFIG['client_secret'],
    }

    try:
        token_response = requests.post(
            OAUTH_CONFIG['token_endpoint'],
            data=refresh_payload,
            headers={
                'Content-Type': 'application/x-www-form-urlencoded',
                'Accept': 'application/json',
            },
            timeout=30,
        )

        if token_response.status_code != 200:
            return jsonify({
                'error': 'refresh_failed',
                'error_description': f'Token refresh returned status {token_response.status_code}',
            }), 400

        token_data = token_response.json()

        # Update session with new tokens
        session['access_token'] = token_data.get('access_token')
        if 'refresh_token' in token_data:
            session['refresh_token'] = token_data['refresh_token']
        session['expires_in'] = token_data.get('expires_in')

        return jsonify({
            'message': 'Token refreshed successfully',
            'expires_in': token_data.get('expires_in'),
        })

    except requests.exceptions.RequestException as e:
        return jsonify({
            'error': 'refresh_request_error',
            'error_description': str(e),
        }), 500


@app.route('/logout')
def logout():
    """Clear the session and log the user out."""
    session.clear()
    return jsonify({
        'message': 'You have been logged out.',
        'links': {
            'login': url_for('login', _external=True),
        }
    })


def fetch_user_info(access_token):
    """Fetch user information from the authorization server's userinfo endpoint."""
    headers = {
        'Authorization': f'Bearer {access_token}',
        'Accept': 'application/json',
    }

    response = requests.get(
        OAUTH_CONFIG['userinfo_endpoint'],
        headers=headers,
        timeout=30,
    )

    if response.status_code == 401:
        raise Exception('Access token is invalid or expired')

    response.raise_for_status()
    return response.json()


